import{r as a,o as t,a as o,b as e,d as r,F as l,c as n,e as c}from"./app.d8523fce.js";import{_ as s}from"./plugin-vue_export-helper.21dcd24c.js";const d={},p=n('<h1 id="_6-2-vulnerable-components-detection" tabindex="-1"><a class="header-anchor" href="#_6-2-vulnerable-components-detection" aria-hidden="true">#</a> 6.2 Vulnerable Components Detection</h1><h2 id="how-do-i-know-if-my-application-has-vulnerable-components" tabindex="-1"><a class="header-anchor" href="#how-do-i-know-if-my-application-has-vulnerable-components" aria-hidden="true">#</a> How do I know if my application has vulnerable components ?</h2><p><strong>Software composition Analysis</strong> (SCA) tools enable you to <strong>perform automated scan</strong> of all client-side and server-side components, and their dependencies used in your web application. These SCA tools continuously monitor vulnerabilities databases like NVD or OSS Index and alert you of potential threats in your project. Here is a list of SCA tools we recommend to use: Dependency-Track, Dependency-Check, retire.js</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>SCA reports requires further analysis from your end in order to identify the real impact based on your context and filter out false positives.</p></div><h2 id="detecting-known-vulnerable-javascript-libraries-with-retire-js" tabindex="-1"><a class="header-anchor" href="#detecting-known-vulnerable-javascript-libraries-with-retire-js" aria-hidden="true">#</a> Detecting known vulnerable JavaScript libraries with Retire.js</h2>',5),h={href:"http://retirejs.github.io/retire.js/",target:"_blank",rel:"noopener noreferrer"},u=c("Retire.js Setup Guide"),m=n('<p>Features :</p><ul><li>For Single Page Application , NodeJS apps, traditional web applications</li><li>Scan js files, bower and node modules</li><li>List vulnerabilities with corresponding CVE code, a link to the detail (changelog, issue github, ...)</li></ul><p>Usage :</p><ul><li>command line</li><li>grunt</li><li>gulp task</li><li>browser plugin</li><li>pentest tool plugin</li></ul><h2 id="detecting-known-vulnerable-maven-dependencies-with-dependency-check" tabindex="-1"><a class="header-anchor" href="#detecting-known-vulnerable-maven-dependencies-with-dependency-check" aria-hidden="true">#</a> Detecting known vulnerable maven dependencies with Dependency-Check</h2><ul><li><p>Dependency-Check: Open source, maven plugin</p></li><li><p>Features:</p><ul><li>Scan all maven dependencies</li><li>Access to the NVD and check CVE</li><li>Generate a complete report (HTML format): vulnerabilitties, criticality level, CVE code, patched versions ...</li></ul></li><li><p>Execute the maven command mvn org.owasp:dependency-check-maven:check</p></li><li><p>See usage &amp; configuration</p></li></ul><h2 id="tracking-project-vulnerabilities-with-dependency-track" tabindex="-1"><a class="header-anchor" href="#tracking-project-vulnerabilities-with-dependency-track" aria-hidden="true">#</a> Tracking project vulnerabilities with Dependency-Track</h2><p>Dependency-Track is an Open source tool provided by OWASP which allows continuous component analysis.</p><p>Features:</p><ul><li>CycloneDX and SPDX bill-of-material formats</li><li>Dependency-Check XML</li><li>Jenkins and gitlab-ci integration</li></ul>',10);function b(v,k){const i=a("ExternalLinkIcon");return t(),o(l,null,[p,e("p",null,[e("a",h,[u,r(i)])]),m],64)}var w=s(d,[["render",b]]);export{w as default};
